@@ -44,17 +44,32 @@

 #include <stdio.h>
 #include <errno.h>
+#include <limits.h>
 #include "local.h"
 #ifdef _THREAD_SAFE
 #include <pthread.h>
 #include "pthread_private.h"
 #endif

+/* standard ftell function.  */
+long
+ftell(fp)
+	register FILE *fp;
+{
+	register off_t rv;
+	rv = ftello(fp);
+	if (rv > LONG_MAX) {
+		errno = EFBIG; 	/* XXX should be EOVERFLOW */
+		return (-1);
+	}
+	return (rv);
+}
+
